        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), n1 = 0, n2 = 0, v = f._language == 'v', g = f.getItem('d66')._controlBehavior;
var l1 = g._getColumnOrder('stt_rec_hd'), l2 = g._getColumnOrder('stt_rec_dh');
var e1 = (v ? 'Thông tin mã khách của lệnh xuất phải giống với đơn hàng hoặc hóa đơn.' : 'Issuing Order should have same customer information as Sales Order or Sales Invoice.');
var e2 = (v ? 'Dữ liệu trong chi tiết chỉ được lấy số liệu từ đơn hàng hoặc hóa đơn.' : 'Data in grid form must be extracted from Sales Order or Sales Invoice.');

if (f._checked) {
  var t = f.getItemValue('ma_kh');
  for (var i = 1; i <= g._rowCount; i++) {
    var v1 = (g._getItemValue(i, l1) != ''), v2 = (g._getItemValue(i, l2) != '');
    if (v1 || v2) {
      var u = g._getItem(i, 1)._customerIdentity;
      if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
      if (t != u) {
        $func.hideWait(id);
        $message.show(e1, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
        f._checked = false;
        break;
      }
      if (f._checked) {
        if (v1) {if (n1 == 0) n1 = 1;}
        else {
          if (v2) {if (n2 == 0) n2 = 1;}
        }
      }
    }
  }
}

if (f._checked) {
  if (n1 + n2 > 1) {
    f._errorWarningObject = g._getItem(1, g._getColumnOrder('ma_vt'));
    $func.hideWait(id);
    $message.show(e2, String.format('var f = $find(\'{0}\');f.focus(\'d66\');f._errorWarningObject.focus()', id));
    f._checked = false;
  }
}

f.setItemValue('ngay_ct', f.getItemValue('ngay_lct'));
/* </flatten> */

