script.text:
      &ScriptVoucherInit;
      &ScriptVoucherNumber;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {
  objectBehavior$Voucher$Number.create(f, 'so_ct', 'ma_nk', 'ngay_lct', 'ma_dvcs');
  f.getItem('d66')._controlBehavior.add_onRender(on$Voucher$GridRender);
  f.add_onResponseComplete(on$Voucher$ResponseComplete);
  f.add_commandEvent(on$Voucher$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  set$Voucher$DefaultValue(f);
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {
  f._voucherNumberBehavior.setFormLayout();
  set$Voucher$DefaultValue(f);
  &VoucherLogHandleStatus;
}
function close$Voucher$(f) {
  try {f.remove_commandEvent(on$Voucher$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Voucher$ResponseComplete);} catch (ex) {}
  try {f.getItem('d66')._controlBehavior.remove_onRender(on$Voucher$GridRender);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  objectBehavior$Voucher$Number.dispose(f);
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d66')._controlBehavior;
  switch (action) {
    case 'Check':
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Explore':
      var o = f.getItem('status');
      if (o.options.length < 4) {
        o.options.add(f._$handleStatus[0]);
        o.options.add(f._$handleStatus[1]);
      }
      &VoucherLogHandleStatusExplore;
      break;
    default:
      break;
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d66'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.getItem("d66")._controlBehavior;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;

    case 'Customer':
      f.setItemControlBehavior('ong_ba', result[0].Value, null, true);
      f.live(f.getItem('ong_ba'));
      break;
    case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      set$Voucher$GridColumns(g);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function set$Voucher$DefaultValue(f) {
  if (f._action == 'New') {
    f.setItemValue('ngay_lct', new Date());
    f.setItemValue('ma_nt', f._baseCurrency);
  }
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  if (f._action != 'View') try {
    var o = f.getItem('status');
    if (!f._$handleStatus) f._$handleStatus = [o.options[2], o.options[3]];
    o.remove(3);
    o.remove(2);
  } catch (ex) {}
}
function on$Voucher$GridRender(sender, eventArgs) {set$Voucher$GridColumns(eventArgs.grid);}
function set$Voucher$GridColumns(g) {
  var f = g.get_element().parentForm, v = $func.trim(f.getItemValue('loai_ct'));
  g._setColumnVisible(g._getColumnOrder('sl_xuat'), (v == 2));
  g._setColumnVisible(g._getColumnOrder('sl_hd'), (v != 2));
  g._setColumnVisible(g._getColumnOrder('sl_giao'), (v != 2));
}
/* </flatten> */
